// La Zendesk View 27247269055517 expone la columna 'updated_by_type' con valor
// 'Usuario final' o 'Agente'. Esta es la fuente de verdad porque Zendesk la calcula
// internamente con conocimiento de Sunshine Conversations (cosa que nosotros no
// podemos hacer fiablemente desde audits o comments — todos los audits del canal
// native_messaging vienen con author_id=-1).
const body = $input.first().json || {};
const rows = Array.isArray(body.rows) ? body.rows : [];

const needs = [];
for (const r of rows) {
  if (r.updated_by_type !== 'Usuario final') continue;
  const ticketId = r.ticket_id;
  if (!ticketId) continue;
  const ru = r.requester_updated_at || null;
  const sinceLastDays = ru ? Math.floor((Date.now() - new Date(ru).getTime()) / 86400000) : null;
  needs.push({
    ticket_id: ticketId,
    subject: r.subject || '(sin asunto)',
    days_since_user_updated: sinceLastDays,
    last_user_update_at: ru,
    updated_by_type: r.updated_by_type,
    url: `https://soporteyurest.zendesk.com/agent/tickets/${ticketId}`
  });
}

needs.sort((a,b) => (a.days_since_user_updated ?? 999) - (b.days_since_user_updated ?? 999));

return [{ json: {
  generated_at: new Date().toISOString(),
  view_id: 27247269055517,
  view_total_rows: rows.length,
  needs_agent_reply_count: needs.length,
  needs_agent_reply_ids_csv: needs.map(n => n.ticket_id).join(','),
  needs_agent_reply: needs
} }];
